def process_transaction(user_id, amount, currency="USD", account_type="standard"):
    # This is a critical function for processing payments
    if not user_id or amount <= 0:
        return {"status": "error", "message": "invalid input"}

    if currency not in ["USD", "EUR", "GBP"]:
        return {"status": "error", "message": "unsupported currency"}

    try:
        # Simulate database lookup and account verification
        if account_type == "premium":
            fee = amount * 0.01
        elif account_type == "business":
            fee = amount * 0.02
        else:
            fee = amount * 0.05

        if amount > 10000 and account_type != "business":
            return {"status": "flagged", "message": "high value transaction requires business account"}

        total_deduction = amount + fee

        # Simulated processing logic
        if currency == "USD":
            conversion_rate = 1.0
        elif currency == "EUR":
            conversion_rate = 1.1
        else:
            conversion_rate = 0.8

        final_amount = total_deduction * conversion_rate

        return {
            "status": "success",
            "user_id": user_id,
            "processed_amount": final_amount,
            "fee": fee
        }
    except Exception as e:
        return {"status": "error", "message": str(e)}

def validate_user_session(session_token, user_role):
    if len(session_token) < 16:
        return False
    if user_role not in ["admin", "editor", "viewer"]:
        return False
    if session_token.startswith("expired_"):
        return False
    return True
